import{_ as e,o as a,c as o,a2 as r}from"./chunks/framework.B8zgMDLd.js";const m=JSON.parse('{"title":"Getting Started Vault","description":"","frontmatter":{},"headers":[],"relativePath":"start/getting-started-vault.md","filePath":"start/getting-started-vault.md"}'),i={name:"start/getting-started-vault.md"};function l(n,t,s,d,c,u){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="getting-started-vault" tabindex="-1">Getting Started Vault <a class="header-anchor" href="#getting-started-vault" aria-label="Permalink to &quot;Getting Started Vault&quot;">​</a></h1><p>The Getting Started vault is a small public sample vault hosted at <a href="https://github.com/refactoringhq/tolaria-getting-started" target="_blank" rel="noreferrer">refactoringhq/tolaria-getting-started</a>.</p><p>It exists to show Tolaria&#39;s conventions without requiring you to restructure your own notes first.</p><h2 id="what-it-demonstrates" tabindex="-1">What It Demonstrates <a class="header-anchor" href="#what-it-demonstrates" aria-label="Permalink to &quot;What It Demonstrates&quot;">​</a></h2><ul><li>Markdown notes with YAML frontmatter.</li><li>Types such as Project, Person, Topic, and Procedure.</li><li>Wikilinks in note bodies.</li><li>Relationship fields in frontmatter.</li><li>A local Git repository that can be connected to a remote later.</li><li>Vault guidance files for AI agents.</li></ul><h2 id="local-only-by-default" tabindex="-1">Local-Only By Default <a class="header-anchor" href="#local-only-by-default" aria-label="Permalink to &quot;Local-Only By Default&quot;">​</a></h2><p>When Tolaria clones the sample, it removes the remote from the local copy. This makes the sample vault disposable. You can edit it freely, commit locally, and delete it later.</p><p>To connect a vault to your own remote, use the bottom status bar remote chip or run <code>Add Remote</code> from the command palette.</p><p>Tolaria also repairs starter-vault guidance files when needed. <code>AGENTS.md</code> is the canonical guidance file, <code>CLAUDE.md</code> is kept as a compatibility shim, and <code>GEMINI.md</code> is only created when you explicitly restore Gemini guidance.</p><h2 id="when-to-move-on" tabindex="-1">When To Move On <a class="header-anchor" href="#when-to-move-on" aria-label="Permalink to &quot;When To Move On&quot;">​</a></h2><p>After you understand the sample, open your own vault. Tolaria does not require a special folder structure: a folder of Markdown files is enough to start.</p>',11)])])}const p=e(i,[["render",l]]);export{m as __pageData,p as default};
